// Obtener la respuesta de Gemini desde el nodo HTTP Request
const response = $input.first().json;

// Extraer el texto de la respuesta (puede venir en diferentes formatos)
let text = '';
try {
  text = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) {
  text = '';
}

// Si no hay texto, intentar con otras estructuras (por si la API cambia)
if (!text && response.choices?.[0]?.message?.content) {
  text = response.choices[0].message.content; // Formato alternativo
}

// Limpiar el texto: eliminar markdown, espacios, etc.
let cleanText = text.trim();

// Si la respuesta viene envuelta en triple backticks json ... ```, extraer solo el JSON
const jsonMatch = cleanText.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
  cleanText = jsonMatch[1];
} else {
  // Si no tiene triple backticks, buscar un objeto JSON directamente
  const objMatch = cleanText.match(/\{[\s\S]*\}/);
  if (objMatch) {
    cleanText = objMatch[0];
  }
}

// Intentar parsear el JSON
let ofertas = { ofertas: [] };
try {
  const parsed = JSON.parse(cleanText);
  // Asegurar que tenga la propiedad "ofertas"
  if (parsed.ofertas && Array.isArray(parsed.ofertas)) {
    ofertas = parsed;
  } else if (Array.isArray(parsed)) {
    // Si devolvió directamente un array
    ofertas = { ofertas: parsed };
  } else if (parsed.titulo) {
    // Si devolvió una sola oferta (no array)
    ofertas = { ofertas: [parsed] };
  }
} catch (e) {
  console.error('Error parsing JSON:', e.message);
  // Si falla, devolver array vacío
  ofertas = { ofertas: [] };
}

// Asegurar que cada oferta tenga todos los campos necesarios (para evitar errores posteriores)
const camposRequeridos = ['titulo', 'empresa', 'ubicacion', 'requisitos_tecnicos', 'anos_experiencia', 'responsabilidades', 'herramientas', 'url_oferta', 'resumen'];
ofertas.ofertas = ofertas.ofertas.map(oferta => {
  const completa = { ...oferta };
  for (const campo of camposRequeridos) {
    if (completa[campo] === undefined) {
      completa[campo] = (campo === 'requisitos_tecnicos' || campo === 'responsabilidades' || campo === 'herramientas') ? [] : null;
    }
  }
  return completa;
});

// Devolver solo el objeto con el array de ofertas
return ofertas;

