const item = $input.first().json;

// Extraer remitente
let fromString = '';
if (typeof item.from === 'string') {
  fromString = item.from;
} else if (item.from?.text) {
  fromString = item.from.text;
} else if (item.from?.value?.[0]) {
  const v = item.from.value[0];
  fromString = `${v.name || ''} <${v.address || ''}>`;
} else {
  fromString = JSON.stringify(item.from);
}

const subject = item.subject || '';
let fullText = item.text || '';

// Recortar a 2000 caracteres (para que la entrada sea más pequeña)
const maxChars = 2000;
let bodyText = fullText.length > maxChars ? fullText.substring(0, maxChars) : fullText;
bodyText = bodyText.replace(/-{5,}/g, '').replace(/\n{3,}/g, '\n\n');

const prompt = `Eres un asistente de reclutamiento. Extrae del siguiente correo TODAS las ofertas de trabajo (máximo 5). Devuelve SOLO un JSON: {"ofertas":[{"titulo":"","empresa":"","ubicacion":"","requisitos_tecnicos":[],"anos_experiencia":null,"responsabilidades":[],"herramientas":[],"url_oferta":null,"resumen":""}]}. Si no hay ofertas, {"ofertas":[]}.

Correo:
De: ${fromString}
Asunto: ${subject}
Cuerpo: ${bodyText}`;

const requestBody = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { temperature: 0, maxOutputTokens: 4000 } // aumentado
};

return { body: JSON.stringify(requestBody) };

const items = $input.all();
const ofertas = items[0]?.json?.ofertas || [];
const perfil = items[1]?.json?.text || '';

const skillsDeseadas = [
  'python', 'sql', 'machine learning', 'data science', 'etl',
  'pandas', 'scikit-learn', 'catboost', 'oracle', 'oci',
  'power bi', 'tableau', 'n8n', 'langgraph', 'rag', 'gemini',
  'agentes ia', 'automatización', 'churn', 'roi', 'predictivo'
];

function calcular(oferta, perfilTexto) {
  let puntaje = 0, coincidencias = [], faltantes = [];
  const ofertaTexto = (oferta.titulo + ' ' + oferta.empresa + ' ' +
                       (oferta.requisitos_tecnicos || []).join(' ') + ' ' +
                       (oferta.responsabilidades || []).join(' ')).toLowerCase();
  const perfilLower = perfilTexto.toLowerCase();
  for (const skill of skillsDeseadas) {
    if (ofertaTexto.includes(skill)) {
      if (perfilLower.includes(skill)) {
        puntaje += 15;
        coincidencias.push(skill);
      } else {
        puntaje -= 5;
        faltantes.push(skill);
      }
    }
  }
  puntaje = Math.min(100, Math.max(0, 50 + puntaje));
  return { puntaje, coincidencias, faltantes };
}

const ofertasConCompatibilidad = ofertas.map(o => ({ ...o, ...calcular(o, perfil) }));
ofertasConCompatibilidad.sort((a, b) => b.puntaje - a.puntaje);
return { ofertas: ofertasConCompatibilidad };
